function MathTutor() {
  const [difficulty, setDifficulty] = React.useState('easy');
  const [problem, setProblem] = React.useState(null);
  const [answer, setAnswer] = React.useState('');
  const [score, setScore] = React.useState({correct:0,total:0});
  const [feedback, setFeedback] = React.useState(null);

  const generate = ()=>{
    let a,b,op,ans;
    if(difficulty==='easy'){a=Math.floor(Math.random()*10)+1;b=Math.floor(Math.random()*10)+1;}
    else if(difficulty==='medium'){a=Math.floor(Math.random()*50)+1;b=Math.floor(Math.random()*50)+1;}
    else{a=Math.floor(Math.random()*100)+10;b=Math.floor(Math.random()*100)+10;}
    const ops = ['+','-','×'];
    op = ops[Math.floor(Math.random()*ops.length)];
    if(op==='+')ans=a+b;
    else if(op==='-')ans=a-b;
    else ans=a*b;
    setProblem({a,b,op,ans});
    setAnswer('');
    setFeedback(null);
  };

  React.useEffect(()=>generate(),[difficulty]);

  const check = ()=>{
    const correct = parseInt(answer)===problem.ans;
    setScore(s=>({correct:s.correct+(correct?1:0),total:s.total+1}));
    setFeedback(correct?'correct':'wrong');
    setTimeout(()=>generate(),800);
  };

  return (
    <div style={{padding:20,fontFamily:'system-ui',height:'100%',display:'flex',flexDirection:'column',alignItems:'center'}}>
      <div style={{fontSize:18,fontWeight:700,marginBottom:8}}>Math Tutor</div>
      <div style={{display:'flex',gap:6,marginBottom:16}}>
        {['easy','medium','hard'].map(d=> (
          <button key={d} onClick={()=>setDifficulty(d)}
            style={{padding:'4px 12px',borderRadius:6,border:'1px solid #ccc',background:difficulty===d?'#007AFF':'#fff',color:difficulty===d?'#fff':'#000',cursor:'pointer',fontSize:12,textTransform:'capitalize'}}>
            {d}
          </button>
        ))}
      </div>
      <div style={{fontSize:14,color:'#888',marginBottom:16}}>Score: {score.correct}/{score.total}</div>
      {problem && (
        <div style={{textAlign:'center'}}>
          <div style={{fontSize:36,fontWeight:200,marginBottom:20,fontVariantNumeric:'tabular-nums'}}>
            {problem.a} {problem.op} {problem.b} = ?
          </div>
          <input type="number" value={answer} onChange={e=>setAnswer(e.target.value)} onKeyDown={e=>e.key==='Enter'&&check()}
            style={{width:100,padding:'10px',borderRadius:8,border:'1px solid #ccc',fontSize:20,textAlign:'center',marginBottom:12}}
            autoFocus/>
          <div style={{marginBottom:12}}>
            <button onClick={check}
              style={{padding:'8px 24px',borderRadius:8,background:'#34C759',color:'#fff',border:'none',cursor:'pointer',fontSize:16}}>
              Check
            </button>
          </div>
          {feedback==='correct'&&<div style={{color:'#34C759',fontWeight:600}}>✓ Correct!</div>}
          {feedback==='wrong'&&<div style={{color:'#FF3B30',fontWeight:600}}>✗ Try again</div>}
        </div>
      )}
    </div>
  );
}
render(<MathTutor/>);
